soc_psy = [
{"id":"5k-so-061","name":"群体极化","domain":"社会心理学","type_id":"18","description":"一群观点相似的人讨论后立场变得更极端——温和的支持变成狂热拥护，因为讨论中论据偏向一方彼此强化，每个人都把同伴的赞同当作自己正确的证据形成正反馈。"},
{"id":"5k-so-062","name":"旁观者冷漠的扩散效应","domain":"社会心理学","type_id":"15","description":"有人晕倒在人群中时每个人都觉得别人会帮忙于是自己不动，责任像水一样向周围扩散被稀释——旁观者越多每个人感受到的行动压力越小最终可能无人施救。"},
{"id":"5k-so-063","name":"社会认同威胁","domain":"社会心理学","type_id":"23","description":"当一个群体的身份认同受到贬低或威胁时成员会出现强烈的防御反应，一旦威胁强度超过某个心理阈值就从温和的不满突然升级为激烈的对抗行为。"},
{"id":"5k-so-064","name":"从众的信息级联","domain":"社会心理学","type_id":"42","description":"每个人都参考前人的选择来做决定，当最初几个人碰巧选了同一个选项后面所有人都跟风，错误的共识像传染病一样在社会网络中蔓延即使大多数人内心存疑。"},
{"id":"5k-so-065","name":"社会比较的上行嫉妒","domain":"社会心理学","type_id":"09","description":"和比自己优秀的人比较时产生的嫉妒感随差距增大而增强，但当差距大到完全不可比时嫉妒反而消失——对遥不可及的人无感只对差距不大的人最嫉妒。"},
{"id":"5k-so-066","name":"少数人影响力","domain":"社会心理学","type_id":"07","description":"一个立场坚定一致的少数派随时间推移能逐渐改变多数人的看法，影响力起初增长很快后来渐渐趋于饱和——少数派能撬动的最大转变量存在一个上限。"},
{"id":"5k-so-067","name":"社会惰化","domain":"社会心理学","type_id":"04","description":"团队合作时个人出力与团队人数成反比——两人组每人出百分之九十的力三人组只有百分之八十到了八人组可能不到一半，总人数越多人均贡献越低。"},
{"id":"5k-so-068","name":"去个体化","domain":"社会心理学","type_id":"25","description":"人在匿名人群中突然变得冲动攻击性增强，仿佛自我意识跨过一个阈值被关掉了——从有约束的个体一下子切换到不受约束的群体状态是一种不连续的质变。"},
{"id":"5k-so-069","name":"态度的免疫效应","domain":"社会心理学","type_id":"58","description":"先让人接触弱化的反对论点并练习反驳，以后遇到更强的说服攻击时就能抵抗——就像疫苗注射弱毒株让心理免疫系统提前建立防线纠正未来可能的信念偏移。"},
{"id":"5k-so-070","name":"内群体偏好的最小群体范式","domain":"社会心理学","type_id":"24","description":"即使按完全随机的标准分成两组人也会立刻偏向自己所在的组——群体边界的出现打破了人际对称性让原本相同的人因为标签不同而被区别对待。"},
{"id":"5k-so-071","name":"替罪羊理论","domain":"社会心理学","type_id":"17","description":"社会压力像流体一样沿着权力梯度向下对流——经济衰退时的焦虑和愤怒从承压的主流群体转移到更弱势的少数群体身上，情绪随对流路径扩散。"},
{"id":"5k-so-072","name":"说服的睡眠效应","domain":"社会心理学","type_id":"22","description":"来自低可信度来源的信息刚听到时没什么影响，但几周后态度却发生了改变——因为信息内容的记忆和来源的记忆衰减速度不同产生了时间滞后效应。"},
{"id":"5k-so-073","name":"社会促进与抑制","domain":"社会心理学","type_id":"24","description":"有人观看时熟练的任务表现更好而困难的任务表现更差——他人在场像一个分岔点把表现推向两个对称相反的方向取决于任务难度落在哪一侧。"},
{"id":"5k-so-074","name":"规范性社会影响的阈值模型","domain":"社会心理学","type_id":"23","description":"每个人都有一个从众阈值——需要看到一定比例的人行动才会跟随，阈值低的人先动起来带动更多人超过各自的阈值像多米诺一样依次触发。"},
{"id":"5k-so-075","name":"权威服从的渐进承诺","domain":"社会心理学","type_id":"07","description":"米尔格拉姆实验中参与者从轻微电击开始一步步升级到危险水平，每一步的增量很小以至于找不到拒绝的理由，服从程度像S形曲线一样逐步爬升最终趋于完全服从。"},
{"id":"5k-so-076","name":"社会交换中的公平偏好","domain":"社会心理学","type_id":"19","description":"人在分配资源时不仅考虑自己得多少还在意和别人比是否公平，偏离公平的方案会引发惩罚行为把分配拉回均等——偏离越大惩罚力度越强形成自动纠偏。"},
{"id":"5k-so-077","name":"刻板印象威胁","domain":"社会心理学","type_id":"18","description":"提醒某群体的负面刻板印象后该群体成员表现真的变差了——焦虑占用了认知资源导致发挥失常而失常的结果又强化了刻板印象形成自证预言。"},
{"id":"5k-so-078","name":"道德脱离","domain":"社会心理学","type_id":"25","description":"通过语言重新标记把伤害行为说成正当行为后道德自我审查突然关闭——从有罪恶感到毫无愧疚之间是一个非连续的跳变而非渐进的减弱。"},
{"id":"5k-so-079","name":"接触假说","domain":"社会心理学","type_id":"06","description":"不同群体之间的偏见随平等接触次数增加而逐渐减少，最初下降很快后来趋于平缓——偏见像放射性物质一样在持续接触中衰减但永远不会完全归零。"},
{"id":"5k-so-080","name":"社会网络中的弱关系优势","domain":"社会心理学","type_id":"44","description":"找工作时最有用的信息往往来自不太熟的朋友而非密友因为弱关系连接着不同的社交圈——信息必须经过远距离的桥接路径才能到达原本隔绝的领域。"},
{"id":"5k-so-081","name":"情绪传染","domain":"社会心理学","type_id":"42","description":"一个人的坏情绪能传给身边的人然后继续扩散，每个人既是接收者又是传播者——情绪像病毒一样在社交网络中级联传播一个人的愤怒可以感染整个办公室。"},
{"id":"5k-so-082","name":"认知吝啬鬼","domain":"社会心理学","type_id":"49","description":"人在形成对他人的印象时倾向于使用最省力的策略，从最容易获取的信息出发用最小的认知投入达到一个'够用'的判断——像梯度下降一样找到局部最优就停下。"},
{"id":"5k-so-083","name":"多元无知","domain":"社会心理学","type_id":"71","description":"群体中每个人都私下反对某个规范但以为其他人都支持于是谁也不敢开口，错误的共识被固定在一个没人真正赞同的状态上像一个虚假的不动点。"},
{"id":"5k-so-084","name":"互惠规范的螺旋升级","domain":"社会心理学","type_id":"18","description":"你送我一份礼我还一份更大的你再还更大的——互惠义务不断升级每一轮的回报都比上一轮更多形成礼物经济中的正反馈螺旋。"},
{"id":"5k-so-085","name":"聚光灯效应","domain":"社会心理学","type_id":"36","description":"人总觉得别人注意自己的程度远超实际——穿了一件尴尬的T恤以为全世界都看到了其实几乎没人注意，对被关注程度的主观估计系统性地偏离客观事实。"},
{"id":"5k-so-086","name":"社会距离折扣","domain":"社会心理学","type_id":"09","description":"人对他人不幸的共情程度随社会距离增大而迅速衰减——对家人的痛苦感同身受对邻居的不幸有些担忧对远方陌生人的灾难只是一条新闻。"},
{"id":"5k-so-087","name":"后见之明偏差","domain":"社会心理学","type_id":"71","description":"事情发生后人们觉得自己早就料到了结果然后把信念锁定在这个已知结果上——记忆被改写成'我一直就是这么想的'形成一个回溯性的不动点。"},
{"id":"5k-so-088","name":"自我妨碍","domain":"社会心理学","type_id":"19","description":"担心失败的人故意给自己设置障碍——如果失败了可以归咎于障碍保护自尊如果成功了更显能力出众。这种策略通过负反馈把自尊维持在一个安全水平。"},
{"id":"5k-so-089","name":"敌意归因偏差","domain":"社会心理学","type_id":"18","description":"有攻击倾向的人把别人的无心之举解读为恶意挑衅然后做出攻击反应对方被迫反击真的产生了敌意——最初的误判通过互动变成了现实的自我实现预言。"},
{"id":"5k-so-090","name":"群体思维","domain":"社会心理学","type_id":"72","description":"高凝聚力的决策团队过于追求一致意见压制异议最终做出灾难性决策——单个成员都是理性的但互动产生的集体愚蠢远超任何个人失误的简单加总。"},
{"id":"5k-so-091","name":"社会标记理论","domain":"社会心理学","type_id":"18","description":"一个人被贴上'越轨者'标签后社会排斥把他推向越轨群体他获得更多越轨技能和认同变得更加越轨——标签产生了它所描述的现实。"},
{"id":"5k-so-092","name":"虚假独特性效应","domain":"社会心理学","type_id":"36","description":"人们倾向于高估自己好品质的独特性——觉得自己比大多数人更善良更聪明更客观——对自身优势频率的主观估计系统性地偏离群体的统计分布。"},
{"id":"5k-so-093","name":"认知一致性压力","domain":"社会心理学","type_id":"45","description":"人倾向于让自己的信念、态度和行为保持一致当出现矛盾时会调整各个成分使总体不一致程度最小化——像在约束条件下寻找让心理紧张最低的最优状态。"},
{"id":"5k-so-094","name":"沉默螺旋中的多数幻觉","domain":"社会心理学","type_id":"18","description":"一方声音越大另一方越沉默沉默又让前者看起来更占多数声音更大——即使双方人数相当感知到的力量对比也会被正反馈放大到一边倒。"},
{"id":"5k-so-095","name":"态度极化的重复暴露","domain":"社会心理学","type_id":"28","description":"反复接触同一信息会强化已有态度，正面态度变更正面负面变更负面，态度随暴露次数的增加而分叉——就像倍周期分岔一样原本中性的立场分裂为两个极端。"},
{"id":"5k-so-096","name":"社会支持的缓冲模型","domain":"社会心理学","type_id":"23","description":"压力对健康的损害只有在缺乏社会支持时才显现，有足够支持时即使压力很大健康也能维持——社会支持像一道防线压力超过它才开始造成伤害。"},
{"id":"5k-so-097","name":"相对剥夺感","domain":"社会心理学","type_id":"19","description":"人的不满不取决于绝对境遇而取决于和参照群体的差距——经济增长了但别人增长更快反而更愤怒，主观感受自动向一个公平标准回归偏离越大不满越强。"},
{"id":"5k-so-098","name":"团体凝聚力的倒U曲线","domain":"社会心理学","type_id":"45","description":"团体凝聚力太低成员不合作凝聚力太高则压制异议导致群体思维最优绩效出现在中等凝聚力水平——需要在团结和多样性之间找到最佳平衡点。"},
{"id":"5k-so-099","name":"态度改变的中心与边缘路径","domain":"社会心理学","type_id":"24","description":"高动机时走中心路径被论据质量说服低动机时走边缘路径被外观和名人效应影响——动机水平像一个分叉点决定说服走向截然不同的两条加工路线。"},
{"id":"5k-so-100","name":"自我效能的螺旋","domain":"社会心理学","type_id":"18","description":"相信自己能做到的人更努力于是更容易成功成功体验又增强了自信——信念和成就互相推动形成正反馈让强者愈强弱者愈弱。"},
{"id":"5k-so-101","name":"助人行为的代价-收益分析","domain":"社会心理学","type_id":"45","description":"看到有人需要帮助时旁观者下意识权衡帮忙的成本和不帮的内疚感寻找让总体不适最小的选择——有时选择帮忙有时选择离开取决于哪种行动的心理代价最低。"},
{"id":"5k-so-102","name":"印象形成的首因效应","domain":"社会心理学","type_id":"21","description":"最初获得的关于一个人的信息对整体印象影响最大后续信息很难改变初始判断——第一印象形成了一种心理滞后使后来的矛盾信息被低估或重新解释。"},
{"id":"5k-so-103","name":"群际威胁的现实冲突","domain":"社会心理学","type_id":"51","description":"两个群体争夺同一份有限资源时不可避免地陷入冲突每方的合理争取对另一方都是威胁——利益结构使得合作几乎不可能双方都被锁在对抗中。"},
{"id":"5k-so-104","name":"社会地位的马太效应","domain":"社会心理学","type_id":"05","description":"已有声望的人更容易获得机会更多机会带来更多成就更多成就带来更大声望——初始的小优势通过指数放大变成巨大的地位鸿沟。"},
{"id":"5k-so-105","name":"道德许可效应","domain":"社会心理学","type_id":"10","description":"做了一件好事后人觉得攒够了道德积分接下来就放纵一下然后再用好行为补回来——道德行为在善与恶之间来回振荡像钟摆一样周期波动。"},
{"id":"5k-so-106","name":"集体效能信念","domain":"社会心理学","type_id":"72","description":"团队成员对团队整体能力的信念比个体能力的简单求和更能预测团队表现——共享的信心创造了超越个体贡献总和的集体行动力。"},
{"id":"5k-so-107","name":"公正世界信念","domain":"社会心理学","type_id":"71","description":"人们相信世界是公正的好人有好报坏人有恶报于是当看到无辜的受害者时反而责怪受害者——信念像一个吸引子把对事件的解释不断拉向'报应'框架。"},
{"id":"5k-so-108","name":"归因的行动者-观察者偏差","domain":"社会心理学","type_id":"81","description":"同一个行为自己做的时候归因于情境别人做的时候归因于性格——对自身行为和他人行为的解释方式互为对偶形成一种系统性的归因不对称。"},
{"id":"5k-so-109","name":"社会两难中的搭便车","domain":"社会心理学","type_id":"51","description":"公共物品大家都能享用但贡献要自己出个体最优策略是让别人出力自己享受成果——如果每个人都这么想公共物品就无人提供理性个体导致集体灾难。"},
{"id":"5k-so-110","name":"社会网络的结构洞","domain":"社会心理学","type_id":"44","description":"两个不相连的社交圈之间存在信息真空谁能架起桥梁谁就占据信息优势——占据结构洞的人控制了两个圈子之间最短信息路径获得不对称的权力。"},
]
entries.extend(soc_psy)

# ============================================================
# 3. 发展心理学 (40 条)
# ============================================================
dev_psy = [
{"id":"5k-so-111","name":"语言习得关键期","domain":"发展心理学","type_id":"23","description":"儿童在大约两到十二岁之间学习语言极其高效过了这个窗口期学习能力骤然下降——语言能力的可塑性在临界年龄处经历一次不可逆的阶梯式跌落。"},
{"id":"5k-so-112","name":"安全型依恋的内部工作模型","domain":"发展心理学","type_id":"71","description":"婴儿与主要照料者形成的安全依恋关系内化为一个心理模板此后所有亲密关系都被这个模板吸引——成年后的关系模式趋向于重复最初的依恋体验。"},
{"id":"5k-so-113","name":"皮亚杰的认知发展阶段","domain":"发展心理学","type_id":"25","description":"儿童的思维能力不是平滑增长的而是经历几次质的飞跃——从感觉运动到前运算再到具体运算最后到形式运算每次转变都是认知结构的整体重组。"},
{"id":"5k-so-114","name":"科尔伯格道德发展阶段","domain":"发展心理学","type_id":"73","description":"道德推理从自利避罚到遵守规则再到普遍原则逐级发展形成一棵层次树——每一层以前一层为基础但增加了更抽象的组织原则。"},
{"id":"5k-so-115","name":"最近发展区","domain":"发展心理学","type_id":"23","description":"儿童独立能完成的任务和在帮助下能完成的任务之间有一个窗口区——教学只有落在这个区间内才有效太简单没有增长太难超过了脚手架能支撑的范围。"},
{"id":"5k-so-116","name":"婴儿的习惯化-去习惯化范式","domain":"发展心理学","type_id":"06","description":"反复给婴儿看同一图片他的注视时间逐渐减少说明已经习惯了换一张新图片注视时间猛然恢复——注意力随重复呈现指数衰减遇到新刺激则骤然回升。"},
{"id":"5k-so-117","name":"依恋的矛盾型模式","domain":"发展心理学","type_id":"13","description":"矛盾型依恋的儿童在寻求亲近和抗拒接触之间来回摆荡——不能稳定在亲近也不能稳定在独立而是在两种状态之间持续振荡形成极限环。"},
{"id":"5k-so-118","name":"气质的适配模型","domain":"发展心理学","type_id":"46","description":"儿童发展结果不取决于气质本身也不取决于环境本身而取决于两者的匹配程度——高活跃气质遇到接纳型父母和限制型父母会导向截然不同的发展轨迹。"},
{"id":"5k-so-119","name":"早期剥夺的敏感期效应","domain":"发展心理学","type_id":"21","description":"在关键期内遭受严重忽视的儿童即使后来进入良好环境某些能力也无法完全恢复——早期经历造成的发展缺陷具有滞后效应部分损害是不可逆的。"},
{"id":"5k-so-120","name":"心理理论的发展","domain":"发展心理学","type_id":"25","description":"大约四岁时儿童突然能理解别人可以持有和自己不同的错误信念——这不是渐进学会的而是一种认知跃迁像开关打开一样从完全不理解到瞬间掌握。"},
{"id":"5k-so-121","name":"同伴关系的层级结构","domain":"发展心理学","type_id":"73","description":"儿童社交网络自发形成层次结构——核心好友圈外围是较疏松的玩伴群再外围是点头之交每一层的亲密度和互动频率递减形成嵌套的树状关系。"},
{"id":"5k-so-122","name":"青春期身份认同危机","domain":"发展心理学","type_id":"24","description":"青少年在多种可能的身份之间探索最终必须做出选择——职业方向、价值观、社会角色都面临分岔每个选择排除了其他可能性身份从此不再对称。"},
{"id":"5k-so-123","name":"双语发展的竞争模型","domain":"发展心理学","type_id":"46","description":"两种语言在大脑中争夺激活资源当使用一种语言时另一种被抑制——两个语言系统的竞争达到某种均衡取决于各自的暴露频率和使用场景。"},
{"id":"5k-so-124","name":"执行功能的缓慢成熟","domain":"发展心理学","type_id":"07","description":"儿童的计划、抑制和灵活性等执行功能从幼年到青少年期持续发展进步速度先快后慢到二十岁左右趋于成熟——发展曲线呈S形最终到达一个平台。"},
{"id":"5k-so-125","name":"选择性缄默的维持机制","domain":"发展心理学","type_id":"18","description":"焦虑的孩子在特定场合不说话于是不获得社交练习焦虑没有减少下次更不敢说话——沉默和焦虑互相维持形成越来越牢固的恶性循环。"},
{"id":"5k-so-126","name":"儿童游戏的阶段演进","domain":"发展心理学","type_id":"73","description":"从独自游戏到平行游戏到联合游戏再到合作游戏社交复杂度逐级上升——每个阶段以前一阶段为基础形成一棵发展的层次树。"},
{"id":"5k-so-127","name":"婴儿的统计学习","domain":"发展心理学","type_id":"36","description":"婴儿通过追踪音节共现频率自动发现词语边界——高频连续出现的音节被归为一个词低频转换处被判定为边界本质上是用统计规律更新对语言结构的内部模型。"},
{"id":"5k-so-128","name":"情绪调节的外部到内部转变","domain":"发展心理学","type_id":"19","description":"婴儿靠父母抚慰来调节情绪随着发展逐渐内化了调节策略——外部调节减少内部调节增加总调节能力保持稳定形成从外部反馈到自我反馈的转移。"},
{"id":"5k-so-129","name":"道德内化的三水平","domain":"发展心理学","type_id":"73","description":"儿童的道德遵守从外部惩罚驱动到内化规则再到自主原则依次递进——每一层抽象程度更高形成前习俗、习俗、后习俗的层级结构。"},
{"id":"5k-so-130","name":"同龄人影响的青春期峰值","domain":"发展心理学","type_id":"12","description":"对同伴评价的敏感性在青春期中段达到峰值——社会评价频率恰好和自我意识觉醒频率匹配时影响力最大像共振一样在特定年龄段产生最强效果。"},
{"id":"5k-so-131","name":"安斯沃斯陌生情境中的回避型依恋","domain":"发展心理学","type_id":"11","description":"回避型依恋的婴儿在母亲离开和回来时表面平静但生理指标显示高度唤醒——表现为情绪的过度抑制然后在安全时才逐渐释放像受到阻尼的振荡缓慢回到基线。"},
{"id":"5k-so-132","name":"性别图式的自我强化","domain":"发展心理学","type_id":"18","description":"儿童一旦形成性别图式就选择性地注意和记忆符合图式的信息忽略不符的——图式引导注意注意强化图式越来越刻板化。"},
{"id":"5k-so-133","name":"元认知发展的阶梯","domain":"发展心理学","type_id":"25","description":"儿童对自己认知过程的了解经历几次跳跃式进步——从不知道自己不知道到知道自己不知道再到能策略性地监控自己的学习每一步都是质变。"},
{"id":"5k-so-134","name":"亲子依恋的代际传递","domain":"发展心理学","type_id":"75","description":"父母自身的依恋模式会传递给下一代——安全型父母养出安全型孩子不安全型传递不安全当前的教养方式主要由上一代的经历决定形成代际自回归。"},
{"id":"5k-so-135","name":"弹性发展","domain":"发展心理学","type_id":"19","description":"一些经历逆境的儿童在保护因素作用下仍能正常发展——保护因素起到负反馈的缓冲作用风险因素推偏发展保护因素拉回正轨两者拉锯维持适应性。"},
{"id":"5k-so-136","name":"自我概念的镜像建构","domain":"发展心理学","type_id":"18","description":"儿童通过他人的反应来了解自己——被夸聪明就觉得自己聪明被骂笨就觉得笨他人的评价塑造了自我概念自我概念又影响行为引发新的评价。"},
{"id":"5k-so-137","name":"延迟满足的发展","domain":"发展心理学","type_id":"07","description":"幼儿几乎无法抵抗即时诱惑但随年龄增长等待能力逐渐增强到学龄期基本具备——延迟满足能力的增长呈S形曲线早期进步快到一定年龄后渐趋稳定。"},
{"id":"5k-so-138","name":"守恒概念的突然获得","domain":"发展心理学","type_id":"25","description":"儿童在某个时刻突然理解把水从矮杯倒进高杯水量不变——之前怎么解释都不懂之后一下子全明白了概念的获得是一次认知相变而非渐进积累。"},
{"id":"5k-so-139","name":"早期数感的近似系统","domain":"发展心理学","type_id":"03","description":"婴儿天生能区分数量但精度随数量增大而下降——区分八和十六容易区分八和九很难，辨别能力与数量之比呈对数关系大数之间需要更大的比例差异。"},
{"id":"5k-so-140","name":"友谊概念的层级演进","domain":"发展心理学","type_id":"73","description":"儿童对友谊的理解从'一起玩的人'到'互相帮助的人'再到'分享内心世界的人'逐级发展——每一层包含更深的互惠和亲密形成嵌套的理解层次。"},
{"id":"5k-so-141","name":"模仿学习的选择性过滤","domain":"发展心理学","type_id":"57","description":"幼儿不是无差别模仿所有行为而是选择性地模仿有能力、有权威的示范者——信息过滤器只让特定来源的行为通过其他来源被自动阻挡。"},
{"id":"5k-so-142","name":"发展的关键期窗口关闭","domain":"发展心理学","type_id":"66","description":"某些能力的发展窗口在特定年龄后永久关闭就像一个状态机从开放状态不可逆地转入关闭状态——系统在时间触发下完成状态转换再无回头路。"},
{"id":"5k-so-143","name":"新生儿的交替吸吮偏好","domain":"发展心理学","type_id":"10","description":"新生儿在两种声音刺激之间有节律地改变吸吮频率——快吸一阵听母亲声音慢吸一阵听陌生声音来回切换形成一种自发的振荡性探索行为。"},
{"id":"5k-so-144","name":"同伴拒绝的累积效应","domain":"发展心理学","type_id":"05","description":"被同伴持续排斥的儿童社交技能越来越差被排斥的概率越来越大负面经历以指数方式积累——每一次拒绝都增加了未来被拒绝的可能性。"},
{"id":"5k-so-145","name":"自传体记忆的发展性遗忘","domain":"发展心理学","type_id":"06","description":"成人几乎想不起三岁之前的事情早期记忆随时间快速衰减——这种童年遗忘比普通遗忘更为彻底最初几年的记忆痕迹几乎完全消失。"},
{"id":"5k-so-146","name":"青少年风险决策的双系统失衡","domain":"发展心理学","type_id":"12","description":"青春期情绪系统发育快而控制系统发育慢两者的成熟度落差在十五六岁最大——冲动频率和控制能力的频率不匹配时行为最不稳定像失调的共振。"},
{"id":"5k-so-147","name":"亲社会行为的情境阈值","domain":"发展心理学","type_id":"23","description":"儿童在友善环境中表现亲社会行为但环境恶化到一定程度时亲社会行为突然消失转为自我保护——情境压力超过阈值后行为模式发生不连续的切换。"},
{"id":"5k-so-148","name":"幼儿词汇爆发期","domain":"发展心理学","type_id":"05","description":"婴儿在积累了约五十个词之后词汇量突然开始爆发式增长每天能学好几个新词——慢启动之后进入快速指数增长阶段新词学习速度越来越快。"},
{"id":"5k-so-149","name":"情绪理解的递归深化","domain":"发展心理学","type_id":"70","description":"儿童从识别基本情绪到理解混合情绪再到理解对情绪的情绪层层深入——每一层都以前一层为基础形成递归式的情绪认知其复杂度逐层翻倍。"},
{"id":"5k-so-150","name":"发展的等终性","domain":"发展心理学","type_id":"71","description":"不同起点的儿童经过不同发展路径最终可能达到相似的发展水平——像多条河流汇入同一个湖泊发展结局像一个吸引子把多样的轨迹拉向同一终点。"},
]
entries.extend(dev_psy)

# ============================================================
# 4. 临床心理学 (40 条)
# ============================================================
clin = [
{"id":"5k-so-151","name":"创伤后成长","domain":"临床心理学","type_id":"25","description":"经历严重创伤后一部分人不仅恢复还实现了人格升华——价值观和人生意义发生质的转变，这不是渐进的适应而是一次痛苦触发的认知重构跃迁。"},
{"id":"5k-so-152","name":"习得性无助","domain":"临床心理学","type_id":"71","description":"反复经历无法控制的负面事件后个体停止了一切尝试即使情况改变了也不再行动——无助感形成一个稳定的心理不动点把所有的努力动机都吸收殆尽。"},
{"id":"5k-so-153","name":"暴露疗法的焦虑消退","domain":"临床心理学","type_id":"06","description":"让恐惧症患者反复面对害怕的对象而不发生真正的伤害焦虑水平每次都比上次低——恐惧反应像放射性物质一样随暴露次数指数衰减。"},
{"id":"5k-so-154","name":"抑郁的认知三角","domain":"临床心理学","type_id":"18","description":"对自己、世界和未来都持消极看法这三种消极信念互相证实——觉得自己没用所以世界冷酷所以未来无望而绝望又证实了自己没用形成封闭的正反馈环。"},
{"id":"5k-so-155","name":"创伤记忆的闪回","domain":"临床心理学","type_id":"78","description":"创伤幸存者在日常生活中会突然被一个气味或声音触发而重新体验创伤场景——这种闪回不是持续的而是间歇性突发的在平静中毫无预警地爆发。"},
{"id":"5k-so-156","name":"强迫-焦虑循环","domain":"临床心理学","type_id":"13","description":"侵入性想法引发焦虑强迫行为暂时缓解焦虑但很快焦虑又升起需要更多强迫行为——焦虑和强迫在一个稳定的极限环中持续循环永不自行停止。"},
{"id":"5k-so-157","name":"物质依赖的耐受性","domain":"临床心理学","type_id":"03","description":"反复使用某种药物后需要更大的剂量才能达到同样的效果——效果与剂量的关系呈对数特征初期小量就有明显效果后期剂量翻倍也只增加一点点感觉。"},
{"id":"5k-so-158","name":"恐慌发作的灾难化解释","domain":"临床心理学","type_id":"18","description":"轻微的心悸被解释为心脏病发作恐惧导致更多身体症状更多症状进一步证实灾难即将到来——身体感觉和灾难化想法互相放大在几分钟内升级为全面恐慌。"},
{"id":"5k-so-159","name":"心理治疗的剂量-效应关系","domain":"临床心理学","type_id":"03","description":"治疗次数越多改善越大但边际收益递减——前几次治疗进步最明显之后每增加几次带来的额外改善越来越小遵循对数增长模式。"},
{"id":"5k-so-160","name":"解离的阈值触发","domain":"临床心理学","type_id":"23","description":"当心理痛苦超过个体承受极限时意识突然断裂——从正常状态切换到麻木或恍惚状态这不是渐进变化而是在阈值处发生的突然跳变。"},
{"id":"5k-so-161","name":"双相情感障碍的情绪周期","domain":"临床心理学","type_id":"10","description":"患者在躁狂和抑郁之间周期性摆动——一段时间极度亢奋精力充沛接着跌入深度低落然后又慢慢回升情绪像钟摆一样在两个极端之间往复振荡。"},
{"id":"5k-so-162","name":"戒断反应的反弹","domain":"临床心理学","type_id":"11","description":"停止使用镇静类药物后出现与药效相反的症状——镇静药停了反而焦虑失眠程度超过用药前然后逐渐回落在原始水平附近来回波动最终稳定。"},
{"id":"5k-so-163","name":"复发预防的高危情境","domain":"临床心理学","type_id":"23","description":"戒瘾者在特定情境下复发风险骤然升高——压力、社交压力或旧环境线索一旦超过心理防线阈值就可能从完全戒断瞬间切换到全面复吸。"},
{"id":"5k-so-164","name":"认知行为疗法的下行箭头","domain":"临床心理学","type_id":"73","description":"从表层的自动思维追问到中间信念再到核心信念——治疗师层层深入每一层比上一层更抽象更根本形成从表面想法到深层图式的树状层级。"},
{"id":"5k-so-165","name":"习得性乐观","domain":"临床心理学","type_id":"19","description":"通过训练改变对挫折的解释风格从持久的自我归因转为暂时的外部归因——新的乐观解释形成负反馈抵消了消极想法的自我强化趋势。"},
{"id":"5k-so-166","name":"创伤后应激的条件化泛化","domain":"临床心理学","type_id":"15","description":"最初只对创伤相关线索产生恐惧但恐惧反应逐渐扩散到相似的中性刺激——触发范围像墨水渗透一样从原点向外扩展越来越多的东西变得可怕。"},
{"id":"5k-so-167","name":"正念冥想的注意力训练","domain":"临床心理学","type_id":"20","description":"正念练习中不断将走神的注意力拉回当下——每次走神是偏差走神的持续时间是积累拉回时的速度和力度根据偏差大小动态调整形成三重调节。"},
{"id":"5k-so-168","name":"酒精依赖的钟摆反弹","domain":"临床心理学","type_id":"10","description":"长期饮酒时大脑适应了酒精的抑制作用一旦停酒神经系统弹到另一个极端变得过度兴奋——从镇静到过度激活再逐渐回到中间情绪和神经活动在两端振荡。"},
{"id":"5k-so-169","name":"心理弹性的压力接种","domain":"临床心理学","type_id":"58","description":"适度经历可控的压力事件能增强未来应对更大压力的能力——像接种弱毒疫苗一样小剂量的逆境训练了心理防御系统使之能在未来抵抗更强的冲击。"},
{"id":"5k-so-170","name":"边缘型人格的分裂防御","domain":"临床心理学","type_id":"63","description":"把他人非黑即白地分为全好或全坏没有中间地带——评价系统只有零和一两种状态像布尔运算一样不接受任何灰度不是理想化就是贬低。"},
{"id":"5k-so-171","name":"系统脱敏的焦虑层级","domain":"临床心理学","type_id":"73","description":"把恐惧对象从最轻微到最严重排成等级逐级暴露——每克服一级才挑战下一级形成从叶节点到根节点的树状攻略路径。"},
{"id":"5k-so-172","name":"反刍思维的循环陷阱","domain":"临床心理学","type_id":"13","description":"消极想法触发消极情绪消极情绪引出更多消极想法——思维和情绪在一个稳定的循环轨道上转个不停除非外力干预否则不会自行停止。"},
{"id":"5k-so-173","name":"安慰剂效应","domain":"临床心理学","type_id":"18","description":"相信药物有效的预期本身就能产生治疗效果——预期改善感觉改善的感觉又加强了对治疗有效的信念信念和效果互相放大即使药物毫无活性成分。"},
{"id":"5k-so-174","name":"心理创伤的延迟发作","domain":"临床心理学","type_id":"22","description":"有些人在创伤发生后数月甚至数年才出现症状——情绪反应与触发事件之间存在显著的时间延迟仿佛心理系统需要一段潜伏期才做出反应。"},
{"id":"5k-so-175","name":"自伤行为的情绪调节功能","domain":"临床心理学","type_id":"19","description":"自伤行为在短期内显著降低了无法忍受的情绪张力——极端痛苦引发自伤自伤立刻缓解痛苦形成一种危险但有效的负反馈调节回路。"},
{"id":"5k-so-176","name":"社交焦虑的安全行为悖论","domain":"临床心理学","type_id":"18","description":"社交焦虑者通过回避目光接触和少说话来保护自己但这些行为让别人觉得他冷漠从而真的被排斥——自我保护措施反而制造了害怕的结果。"},
{"id":"5k-so-177","name":"动机式访谈的改变阶段","domain":"临床心理学","type_id":"66","description":"行为改变经历前思考、思考、准备、行动、维持五个阶段每个阶段有不同的任务和转换条件——像一个状态机只有满足特定条件才能转入下一状态。"},
{"id":"5k-so-178","name":"哀伤的波浪模型","domain":"临床心理学","type_id":"11","description":"失去亲人后的悲痛不是匀速减轻的而是像波浪一样时强时弱——猛烈的悲痛发作之后暂时平静然后又涌上来但每次波峰都比上一次低振幅逐渐衰减。"},
{"id":"5k-so-179","name":"创伤的代际传递","domain":"临床心理学","type_id":"75","description":"父母未处理的创伤通过教养方式和情绪反应模式传递给下一代——当前一代的心理状态主要由上一代的创伤经历决定形成创伤的自回归链条。"},
{"id":"5k-so-180","name":"群体治疗的治疗因子","domain":"临床心理学","type_id":"72","description":"在群体治疗中个人获得的帮助超过所有成员单独贡献的总和——普遍性体验、互助支持和集体希望产生了一加一大于二的涌现效应。"},
{"id":"5k-so-181","name":"失眠的过度觉醒","domain":"临床心理学","type_id":"18","description":"担心睡不着导致焦虑焦虑让大脑更清醒更清醒更担心睡不着——对失眠的恐惧本身成了维持失眠的主要因素形成不断升级的正反馈循环。"},
{"id":"5k-so-182","name":"心理防御的层级成熟","domain":"临床心理学","type_id":"73","description":"防御机制从最原始的否认和投射到中间的合理化再到成熟的幽默和升华构成一个成熟度阶梯——每一层比下一层更适应性更灵活形成层次化的防御体系。"},
{"id":"5k-so-183","name":"药物-心理治疗的协同效应","domain":"临床心理学","type_id":"72","description":"药物缓解了最严重的症状让患者有能力参与心理治疗心理治疗改善了认知模式减少了对药物的需求——两种治疗联合效果超过各自效果的简单加总。"},
{"id":"5k-so-184","name":"催眠的分离体验","domain":"临床心理学","type_id":"24","description":"催眠状态下意识的自动执行部分和监控部分发生了分离——统一的意识流被分裂为两条平行的加工通道打破了正常清醒时的整合对称性。"},
{"id":"5k-so-185","name":"负性症状的动机衰竭","domain":"临床心理学","type_id":"06","description":"精神分裂症的负性症状表现为动机和情感逐渐枯竭——社交退缩、情感平淡、意志减退像能量在持续泄漏活力水平随时间不断衰减。"},
{"id":"5k-so-186","name":"进食障碍的身体意象扭曲","domain":"临床心理学","type_id":"18","description":"厌食症患者即使极度消瘦仍觉得自己胖于是继续节食体重进一步下降但知觉扭曲不减反增——越瘦越觉得胖越觉得胖越要减构成致命的正反馈。"},
{"id":"5k-so-187","name":"成瘾的激励敏化","domain":"临床心理学","type_id":"05","description":"反复使用成瘾物质后大脑对药物线索的渴求反应不断增强——每次使用都让下次遇到线索时的渴望更强烈敏化程度随使用次数指数级上升。"},
{"id":"5k-so-188","name":"辩证行为疗法的对立整合","domain":"临床心理学","type_id":"81","description":"治疗同时强调接纳当下的自己和推动改变——接纳和改变看似矛盾但在更高层次上互为补充构成一组对偶关系需要在两极之间动态平衡。"},
{"id":"5k-so-189","name":"复杂创伤的症状层叠","domain":"临床心理学","type_id":"67","description":"经历多次创伤后每一次新创伤都在前一次的基础上增加复杂性——情绪失调、人际困难、身份混乱层层叠加每一层都包含与整体相似的破碎模式。"},
{"id":"5k-so-190","name":"正强化陷阱","domain":"临床心理学","type_id":"18","description":"孩子哭闹父母妥协孩子发现哭闹有效下次更使劲哭父母更难坚持再次妥协——每一轮互动都让问题行为更牢固形成越来越难打破的正反馈链。"},
]
entries.extend(clin)

# ============================================================
# 5. 社会学 (50 条)
# ============================================================
sociol = [
{"id":"5k-so-191","name":"制度化过程","domain":"社会学","type_id":"71","description":"某种做法从个别尝试到群体习惯再到正式规则最终变成'理所当然'——一旦制度化就形成一个稳定的不动点抵抗变革新实践很难突破既有框架。"},
{"id":"5k-so-192","name":"社会流动的漏斗效应","domain":"社会学","type_id":"09","description":"向上流动的机会随阶层升高而急剧减少——从底层向上的通道越走越窄每上一级竞争更激烈淘汰率更高呈现加速衰减的特征。"},
{"id":"5k-so-193","name":"城市居住隔离","domain":"社会学","type_id":"68","description":"即使每个人只有微弱的同类偏好也能导致严重的种族隔离——微小的个体偏好通过搬迁的累积效应自发涌现出宏观的隔离格局达到一种自组织临界状态。"},
{"id":"5k-so-194","name":"科层制的铁笼","domain":"社会学","type_id":"71","description":"韦伯描述的理性化官僚体制一旦建立就困住了所有人——效率逻辑自我强化最终变成一个谁也逃不出的稳定结构所有改革尝试都被吸回既有的运作模式。"},
{"id":"5k-so-195","name":"累积优势与地位固化","domain":"社会学","type_id":"05","description":"已有资源的人更容易获得更多资源——教育好找到好工作好工作带来更多收入更多收入让子女教育更好优势以指数速度累积代际之间差距越拉越大。"},
{"id":"5k-so-196","name":"涂尔干的社会团结转型","domain":"社会学","type_id":"25","description":"社会从机械团结过渡到有机团结不是渐变而是在工业化的推动下发生的质的跳跃——团结的基础从相似性突然切换到分工互补是社会结构的相变。"},
{"id":"5k-so-197","name":"越轨行为的标签放大","domain":"社会学","type_id":"18","description":"社会贴的越轨标签改变了被标签者的自我认知和社会机会迫使其更多越轨行为被发现更多则标签更牢固——标签创造了它所描述的现实。"},
{"id":"5k-so-198","name":"社会规范的临界多数","domain":"社会学","type_id":"23","description":"新行为只有被一定比例的人采纳后才能变成主流——在临界点之前推广异常艰难超过之后扩散突然加速像水从结冰到融化一样在关键比例处发生质变。"},
{"id":"5k-so-199","name":"制度惰性","domain":"社会学","type_id":"21","description":"过时的制度即使所有人都知道需要改变也很难改变——改革的阻力在制度运行越久后越大形成一种路径依赖的滞后效应变革总是大幅落后于需求。"},
{"id":"5k-so-200","name":"社会分层的再生产","domain":"社会学","type_id":"75","description":"每一代的阶层位置主要由上一代决定——父母的职业、教育和文化资本传递给子女子女的位置又决定下一代形成阶层的自回归过程。"},
{"id":"5k-so-201","name":"社区衰败的连锁反应","domain":"社会学","type_id":"42","description":"一家商店关门导致街上人流减少相邻商店也难以为继更多商店关门进一步减少人流——衰败像传染病一样在商业网络中级联扩散。"},
{"id":"5k-so-202","name":"士绅化的置换螺旋","domain":"社会学","type_id":"18","description":"中产阶级搬入低收入社区推高房价房价上涨吸引更多中产进入进一步推高房价——正反馈不断加速直到原住民被完全置换。"},
{"id":"5k-so-203","name":"社会资本的网络效应","domain":"社会学","type_id":"40","description":"社会资本的价值取决于社交网络的结构——认识的人中存在大量互不相识的桥接关系比封闭的小圈子更有价值因为信息可以通过少数跳转到达远端。"},
{"id":"5k-so-204","name":"文化滞后","domain":"社会学","type_id":"22","description":"技术变化后文化和价值观需要很长时间才能跟上——物质文明已经进入新阶段但制度和观念还停留在旧时代之间存在明显的时间滞后。"},
{"id":"5k-so-205","name":"角色冲突的压力汇聚","domain":"社会学","type_id":"82","description":"一个人同时扮演母亲、员工和女儿三个角色每个角色都有约束条件要求相互矛盾——必须在有限的时间和精力约束下找到让所有角色冲突最小的分配方案。"},
{"id":"5k-so-206","name":"社会运动的资源动员","domain":"社会学","type_id":"23","description":"不满情绪普遍存在但只有当组织资源——资金、领导力、媒体渠道——积累到一个临界量时社会运动才能真正发动起来从酝酿突然转为爆发。"},
{"id":"5k-so-207","name":"功能分化与系统自治","domain":"社会学","type_id":"43","description":"现代社会分化为政治、经济、法律、科学等独立子系统——每个子系统有自己的运作逻辑形成功能模块化的社区结构彼此之间有明确边界。"},
{"id":"5k-so-208","name":"集体记忆的选择性建构","domain":"社会学","type_id":"59","description":"社会不是记住所有历史而是选择性地保留和遗忘——海量的历史事件被压缩成几个核心叙事和象征形成一种降维处理将复杂的过去简化为可传承的故事。"},
{"id":"5k-so-209","name":"仪式的社会功能","domain":"社会学","type_id":"76","description":"社会通过周期性举行的仪式——年节、纪念日、毕业典礼——反复强化集体认同和价值观，这种周期性的再确认防止了社会凝聚力的自然衰减。"},
{"id":"5k-so-210","name":"越轨的功能主义解释","domain":"社会学","type_id":"19","description":"社会中一定程度的越轨行为反而强化了规范边界——越轨者受到惩罚让守规者更清楚什么是不可接受的通过负面案例的负反馈维持了规范体系的活力。"},
{"id":"5k-so-211","name":"全控机构的身份剥夺","domain":"社会学","type_id":"25","description":"进入监狱或精神病院等全控机构后个人身份被系统性地剥离——从有名字有身份的个体一下子变成编号这种转变是突然的不可逆的像一次身份的相变。"},
{"id":"5k-so-212","name":"不平等的基尼系数演化","domain":"社会学","type_id":"07","description":"经济发展早期不平等加剧中期增速放缓晚期趋于稳定甚至回落——不平等程度随发展阶段呈S形曲线先快速增长再逐渐饱和。"},
{"id":"5k-so-213","name":"社会闭合与排他","domain":"社会学","type_id":"63","description":"精英群体通过学历、语言、社交礼仪设置准入门槛——符合条件进入不符合排除判断是二元的没有中间地带形成一套社会版的布尔过滤器。"},
{"id":"5k-so-214","name":"理性选择的意外后果","domain":"社会学","type_id":"72","description":"每个人都做出了对自己最优的选择但这些选择互动后产生了谁也没预料到的社会结果——宏观现象不是个人意图的简单加总而是涌现出全新的模式。"},
{"id":"5k-so-215","name":"去传统化与个体化","domain":"社会学","type_id":"06","description":"传统社会纽带——家族、宗教、阶级——对个人行为的约束力随现代化进程不断衰减个体越来越自由也越来越孤立约束力像衰减曲线一样逐渐趋向零。"},
{"id":"5k-so-216","name":"社会排斥的累积效应","domain":"社会学","type_id":"05","description":"贫困导致教育不足教育不足导致低收入低收入导致居住条件差差条件又影响下一代教育——每一重劣势都放大前一重形成以指数速度加深的排斥。"},
{"id":"5k-so-217","name":"公共空间的使用分时","domain":"社会学","type_id":"76","description":"同一个城市广场白天是商业区傍晚变成健身场地夜间变成年轻人聚集地——使用群体和功能按时间周期性轮替形成空间使用的季节性节律。"},
{"id":"5k-so-218","name":"风险社会的不确定性分配","domain":"社会学","type_id":"35","description":"现代社会中环境灾难、金融危机等极端风险的影响不是均匀分布而是高度集中在少数群体上——风险分布呈重尾特征大多数人受影响小但少数人承受极端后果。"},
{"id":"5k-so-219","name":"科学知识的社会建构","domain":"社会学","type_id":"36","description":"科学共同体通过实验证据不断修正理论——新发现如果足够有力就推翻旧信念如果不够则维持现状本质上是用新证据更新先验信念的集体贝叶斯过程。"},
{"id":"5k-so-220","name":"城市化的拉力-推力模型","domain":"社会学","type_id":"17","description":"农村的贫困推力和城市的机会拉力共同驱动人口向城市流动——人口像流体一样从高压区域向低压区域对流形成定向的迁移流。"},
{"id":"5k-so-221","name":"社会信任的螺旋","domain":"社会学","type_id":"18","description":"高信任社会中合作顺畅成功经验增强信任信任又促进更多合作——正反馈让高信任社会越来越信任低信任社会越来越猜疑两者渐行渐远。"},
{"id":"5k-so-222","name":"文化同化的代际梯度","domain":"社会学","type_id":"06","description":"移民第一代保留大部分母文化第二代混合第三代几乎完全融入主流——文化特征随代际更替逐渐衰减每一代都比上一代更接近主流文化。"},
{"id":"5k-so-223","name":"贫民窟的自组织秩序","domain":"社会学","type_id":"68","description":"正式制度缺席的贫民窟中自发产生了非正式的治理规则——没有中央规划但居民之间的反复互动自发涌现出分工、仲裁和互助的临界秩序。"},
{"id":"5k-so-224","name":"郊区蔓延的扩散","domain":"社会学","type_id":"15","description":"城市人口向郊区扩散每户人家都想要更大的空间于是向外搬这种搬迁行为在空间上均匀扩散——人口从中心向外渐次稀释浓度随距离递减。"},
{"id":"5k-so-225","name":"代际冲突的周期性","domain":"社会学","type_id":"76","description":"每一代人都觉得上一代保守下一代浮躁这种代际紧张关系随着世代更替周期性地重复——不同内容相同结构的冲突每隔二三十年轮回一次。"},
{"id":"5k-so-226","name":"社会网络的同质性选择","domain":"社会学","type_id":"43","description":"人倾向于和相似的人交往导致社交网络自然分化为内部高度相似的社区——物以类聚形成边界清晰的模块不同模块之间的联系远少于模块内部。"},
{"id":"5k-so-227","name":"数字鸿沟的层叠","domain":"社会学","type_id":"73","description":"数字不平等分多个层次——首先是能否上网其次是使用技能再次是从中获益的能力——每一层以前一层为基础形成嵌套的层级结构底层不通上层无从谈起。"},
{"id":"5k-so-228","name":"道德恐慌的媒体放大","domain":"社会学","type_id":"18","description":"媒体报道某种越轨行为引发公众恐慌恐慌促使更多报道更多报道加剧恐慌——媒体与公众情绪互相放大把一个小问题滚成全社会的道德危机。"},
{"id":"5k-so-229","name":"组织场域的制度同形","domain":"社会学","type_id":"71","description":"同一领域的组织在竞争和模仿压力下越来越像——结构和实践趋同于一个大家都采用的标准模式形成制度化的不动点偏离的组织被压力拉回。"},
{"id":"5k-so-230","name":"不同阶层的婚配模式","domain":"社会学","type_id":"43","description":"人们倾向于在同一阶层内通婚形成封闭的婚姻市场——上层嫁娶上层中层配中层形成内部紧密连接而阶层之间联系稀少的社区化结构。"},
{"id":"5k-so-231","name":"城中村的功能悖论","domain":"社会学","type_id":"81","description":"城中村同时是城市管理的难题和流动人口的庇护所——破败和活力、违规和包容互为一体的对偶属性在同一空间共存消灭任何一面都会失去另一面。"},
{"id":"5k-so-232","name":"社会创新的扩散曲线","domain":"社会学","type_id":"07","description":"新观念的采纳从少数先驱者开始缓慢起步然后在早期多数人群中加速传播到达晚期多数后增长放缓最终趋于饱和——整个过程呈S形曲线。"},
{"id":"5k-so-233","name":"社会时间的制度化","domain":"社会学","type_id":"66","description":"社会通过工作日、假期、退休年龄等制度把连续的时间切割成离散的状态——每个人的生命周期被状态机式地编排从学生到职员到退休人士按预设路径转换。"},
{"id":"5k-so-234","name":"全球城市的等级网络","domain":"社会学","type_id":"73","description":"纽约伦敦东京是全球城市网络的顶层节点以下是区域性枢纽城市再下是二三线城市——资本和信息沿这个层次树从上到下分配形成清晰的等级秩序。"},
{"id":"5k-so-235","name":"环境正义的不对称风险","domain":"社会学","type_id":"35","description":"污染工厂和垃圾填埋场不成比例地集中在低收入和少数族裔社区——环境风险的分布呈重尾特征大多数社区安全但少数社区承受极端的环境负担。"},
{"id":"5k-so-236","name":"消费文化的符号竞赛","domain":"社会学","type_id":"18","description":"人们通过消费品展示社会地位别人跟风购买推高标准于是需要更贵的东西来区分地位——消费门槛和地位焦虑互相推高形成永不停歇的升级竞赛。"},
{"id":"5k-so-237","name":"社会凝聚力的阈值模型","domain":"社会学","type_id":"23","description":"社会共识只需要超过某个关键比例就会快速凝固——低于阈值时各持己见共识无法形成超过之后从众压力突然增大少数人迅速被吸纳形成压倒性一致。"},
{"id":"5k-so-238","name":"劳动分工的有机依赖","domain":"社会学","type_id":"43","description":"现代社会中每个人的专业化程度越高就越依赖他人——社会像一个模块化系统每个模块完成特定功能模块之间通过市场和制度接口紧密耦合。"},
{"id":"5k-so-239","name":"社会流动的天花板效应","domain":"社会学","type_id":"23","description":"底层向上流动到中层相对容易但从中层进入上层极其困难——仿佛存在一个看不见的天花板阈值以下的努力产生回报超过阈值后无论怎么努力都难以突破。"},
{"id":"5k-so-240","name":"仪式化抗议的制度吸纳","domain":"社会学","type_id":"19","description":"激进的社会运动随着时间推移被制度吸纳变成合法的表达渠道——制度像恒温器一样通过适度让步把社会不满控制在安全范围内防止其升级为革命。"},
]
entries.extend(sociol)

# ============================================================
# 6. 人口学 (30 条)
# ============================================================
demo = [
{"id":"5k-so-241","name":"人口转型理论","domain":"人口学","type_id":"07","description":"随着经济发展人口从高出生高死亡转向低出生低死亡——转型过程中人口增长先加速后减速呈S形曲线最终稳定在低增长的新均衡。"},
{"id":"5k-so-242","name":"马尔萨斯陷阱","domain":"人口学","type_id":"19","description":"人口增长快于食物增长导致人均资源减少饥荒和疾病又把人口压回去——人口和资源之间的负反馈把发展水平锁在勉强温饱的均衡点上。"},
{"id":"5k-so-243","name":"移民的正向选择","domain":"人口学","type_id":"36","description":"移民不是随机抽样而是自我筛选的结果——更有能力、更有冒险精神的人更可能移民使得移民群体的素质分布系统性地偏离来源地的整体分布。"},
{"id":"5k-so-244","name":"人口红利的窗口期","domain":"人口学","type_id":"23","description":"劳动年龄人口比例超过一定阈值时经济获得额外推力低于阈值时变成负担——人口红利只在特定人口结构窗口内存在错过了就不可逆地消失。"},
{"id":"5k-so-245","name":"生育率的J形反转","domain":"人口学","type_id":"11","description":"生育率随发展水平提高先是持续下降然后在高度发达国家出现微弱回升——曲线在最低点反弹形成J形像阻尼振荡在新的较低水平附近波动。"},
{"id":"5k-so-246","name":"人口金字塔的形态转变","domain":"人口学","type_id":"25","description":"发展中国家的年龄结构从宽底尖顶的金字塔转变为发达国家的柱状甚至倒三角——人口结构的几何形态发生质的改变不是渐变而是形状的根本重组。"},
{"id":"5k-so-247","name":"城市化的对数增长","domain":"人口学","type_id":"03","description":"城市人口比例随经济发展先快速增长后增速放缓——从百分之二十到五十很快从五十到八十很慢从八十到九十更慢城市化率与发展水平呈对数关系。"},
{"id":"5k-so-248","name":"老龄化的加速效应","domain":"人口学","type_id":"05","description":"低生育率和长寿命叠加让老年人口占比加速增长——老年人越多社会抚养负担越重年轻人越不愿生育使老龄化进一步加速形成自我强化的趋势。"},
{"id":"5k-so-249","name":"婚姻挤压","domain":"人口学","type_id":"82","description":"出生性别比失衡导致成年后一方性别严重过剩——在适婚人口总量约束下男多女少的社会中最底层男性完全无法找到配偶形成结构性的婚配失衡。"},
{"id":"5k-so-250","name":"流动人口的双向选择","domain":"人口学","type_id":"48","description":"迁移决策中推力和拉力同时作用——离开老家和选择目的地各有多种考量最终迁移模式是所有因素综合后的帕累托折衷没有任何选择在所有维度上都最优。"},
{"id":"5k-so-251","name":"人口惯性","domain":"人口学","type_id":"22","description":"即使生育率立刻降到更替水平人口仍会继续增长数十年——因为大量育龄人口已经存在这批人完成生育需要时间人口增长对政策变化存在巨大的时间延迟。"},
{"id":"5k-so-252","name":"死亡率的流行病学转型","domain":"人口学","type_id":"25","description":"主要死因从传染病转为慢性病不是渐变而是在公共卫生改善的推动下发生了质的跳跃——死亡模式经历了一次从急性到慢性的结构性相变。"},
{"id":"5k-so-253","name":"人口密度与城市等级","domain":"人口学","type_id":"02","description":"城市按人口规模排序后排名和人口之间呈幂律关系——最大城市的人口是第二大的两倍是第四大的四倍极少数巨型城市和大量中小城市共存。"},
{"id":"5k-so-254","name":"迁移的链式效应","domain":"人口学","type_id":"42","description":"先期移民在目的地站稳脚跟后带动亲友跟随前来——一个人的迁移触发更多人迁移像传染病一样在社交网络中级联扩散形成移民链。"},
{"id":"5k-so-255","name":"人口结构的回波效应","domain":"人口学","type_id":"76","description":"战后婴儿潮一代在二三十年后自己又产生一个小婴儿潮——出生高峰像波浪一样在代际间周期性地回响每次振幅都比上一次小。"},
{"id":"5k-so-256","name":"预期寿命的收益递减","domain":"人口学","type_id":"03","description":"医疗投入最初能大幅提高预期寿命但继续增加投入带来的额外寿命越来越短——从六十岁提到七十岁比从七十岁提到八十岁容易得多收益呈对数递减。"},
{"id":"5k-so-257","name":"二孩政策的延迟响应","domain":"人口学","type_id":"22","description":"放开二孩后出生率先是短暂上升释放积压需求然后回落到新的更低水平——政策效果存在明显的时间延迟和过冲响应不是立竿见影的。"},
{"id":"5k-so-258","name":"乡村空心化","domain":"人口学","type_id":"06","description":"年轻人持续外流使乡村人口以加速的速度减少——走的人越多留下的机会越少剩余年轻人更有理由离开形成越走越空的衰减趋势。"},
{"id":"5k-so-259","name":"人口压力的马尔萨斯增长","domain":"人口学","type_id":"05","description":"在资源不受约束的假设下人口以每代翻倍的速度指数增长——二十五年翻一倍五十年翻四倍一百年翻十六倍增长速度本身也在不断加快。"},
{"id":"5k-so-260","name":"人口老龄化的抚养比拐点","domain":"人口学","type_id":"23","description":"老年抚养比从缓慢上升突然进入快速攀升阶段——在某个年份少量退休者变成大批退休者社会保障系统从勉强维持瞬间切换到不堪重负。"},
{"id":"5k-so-261","name":"少子化的社会传染","domain":"人口学","type_id":"42","description":"不生孩子的选择在社交网络中传播——身边越多朋友选择不生自己也越倾向于不生这种生育偏好像传染一样在同龄人中级联扩散。"},
{"id":"5k-so-262","name":"城镇化中的棘轮效应","domain":"人口学","type_id":"21","description":"人口一旦从农村迁入城市极少回流即使城市生活不如预期也不愿回去——城镇化率只升不降具有明显的滞后特征上行容易下行极难。"},
{"id":"5k-so-263","name":"移民汇款的乘数效应","domain":"人口学","type_id":"05","description":"海外移民的汇款注入家乡经济后通过消费和投资在当地产生连锁放大——一笔汇款被反复花费每一轮都创造新收入总效应是原始金额的数倍。"},
{"id":"5k-so-264","name":"人口学的第二次转型","domain":"人口学","type_id":"25","description":"发达国家在完成第一次人口转型后又经历了家庭形式的质变——同居替代婚姻、推迟生育、自愿不育成为主流这是一次从制度化家庭到个体化选择的结构性相变。"},
{"id":"5k-so-265","name":"季节性出生模式","domain":"人口学","type_id":"76","description":"出生人数在一年中呈现规律性的波动——北半球九月是高峰三月是低谷这种周期性模式年年重复反映了九个月前受孕的季节性节律。"},
{"id":"5k-so-266","name":"难民流动的推拉动力学","domain":"人口学","type_id":"17","description":"战乱的推力和安全国家的拉力驱动难民像流体一样沿阻力最小的路径迁移——地理障碍、签证政策和社交网络共同塑造了有方向性的人口对流。"},
{"id":"5k-so-267","name":"生育意愿的代际衰减","domain":"人口学","type_id":"06","description":"每一代人的理想子女数都比上一代少——爷爷辈想要五个父辈想要三个当代只想要一两个生育意愿随代际更替持续衰减趋向一个越来越低的下限。"},
{"id":"5k-so-268","name":"人口结构与储蓄率","domain":"人口学","type_id":"10","description":"劳动年龄人口占比高时社会储蓄率高老年占比高时储蓄率低——随着人口结构的周期性变化储蓄率在高低之间振荡反映了人口红利和人口负债的交替。"},
{"id":"5k-so-269","name":"内卷型人口增长","domain":"人口学","type_id":"71","description":"人口增长没有带来人均收入提高而是被更密集的劳动吸收——产出增加了但全被新增人口分掉人均水平始终被钉在同一个点上形成发展的不动点陷阱。"},
{"id":"5k-so-270","name":"超低生育率陷阱","domain":"人口学","type_id":"18","description":"生育率跌到极低水平后育龄女性数量减少即使每个人多生一点总出生数仍在下降出生数下降又减少了未来的育龄女性——低生育自我强化越陷越深。"},
]
entries.extend(demo)

