comm = [
{"id":"5k-so-431","name":"议程设置","domain":"传播学","type_id":"53","description":"媒体不能决定人们怎么想但能决定人们想什么——通过选择报道哪些议题媒体设计了公众讨论的菜单本质上是一种信息呈现的机制设计引导集体注意力。"},
{"id":"5k-so-432","name":"沉默螺旋","domain":"传播学","type_id":"18","description":"感知到自己是少数意见的人倾向于沉默沉默让多数意见显得更强势更多人因此沉默——感知和表达之间的正反馈把公共舆论推向单一声音。"},
{"id":"5k-so-433","name":"框架效应在新闻中的应用","domain":"传播学","type_id":"81","description":"同一事件用'经济发展'框架和'环境破坏'框架报道会引发截然不同的公众反应——两种框架信息内容相同但呈现角度互为对偶激活了不同的判断路径。"},
{"id":"5k-so-434","name":"知识鸿沟假说","domain":"传播学","type_id":"05","description":"新媒体技术的普及不是缩小而是扩大了信息差距——高教育群体吸收信息更快信息差距以加速方式拉大形成知识获取上的马太效应。"},
{"id":"5k-so-435","name":"创新扩散的S曲线","domain":"传播学","type_id":"07","description":"新媒体技术的采用从创新者到早期采用者到早期多数再到晚期多数——采用率先慢后快再慢最终趋于饱和形成典型的逻辑斯蒂增长曲线。"},
{"id":"5k-so-436","name":"两级传播模型","domain":"传播学","type_id":"73","description":"信息从大众媒体先到达意见领袖再由意见领袖传递给普通受众——信息的扩散不是一步到位而是经过层级中转形成媒体到意见领袖到公众的树状传播路径。"},
{"id":"5k-so-437","name":"媒体回声室","domain":"传播学","type_id":"18","description":"算法推荐让人只看到与自己观点一致的内容这些内容强化了原有观点更极端的观点又被算法优先推荐——信息茧房和观点极化互相加强。"},
{"id":"5k-so-438","name":"涵化理论","domain":"传播学","type_id":"07","description":"长期暴露于电视内容后观众的世界观逐渐向电视呈现的画面靠拢——收看时间越长现实感知越接近电视世界偏移程度先快后慢趋于一个上限。"},
{"id":"5k-so-439","name":"信息超载","domain":"传播学","type_id":"23","description":"当可用信息量超过个人处理能力的阈值时决策质量骤然下降——在阈值之下更多信息帮助判断超过之后信息反而成为噪声降低决策准确性。"},
{"id":"5k-so-440","name":"谣言传播的衰减","domain":"传播学","type_id":"06","description":"谣言在传播过程中每转述一次细节就丢失一些可信度也降低——经过多次转述后信息严重失真传播动力指数衰减直到无人再转。"},
{"id":"5k-so-441","name":"病毒式传播","domain":"传播学","type_id":"05","description":"一条引人注目的内容被分享后每个看到的人又分享给多人——传播速度像病毒一样呈指数增长一小时内从一个人到达百万人。"},
{"id":"5k-so-442","name":"媒体的守门人功能","domain":"传播学","type_id":"57","description":"编辑和记者决定哪些新闻能通过'大门'进入公共视野——大量事件竞争有限的版面只有通过信息筛选器的内容才能到达受众。"},
{"id":"5k-so-443","name":"注意力经济的竞争","domain":"传播学","type_id":"51","description":"内容生产者争夺用户有限的注意力——每个平台都试图最大化用户停留时间但用户的注意力总量是固定的给了一个平台就没法给另一个。"},
{"id":"5k-so-444","name":"公共舆论的极化分叉","domain":"传播学","type_id":"28","description":"社交媒体上温和意见逐渐消失舆论分裂为两个极端阵营——中间立场在反复讨论中不断分叉每次分叉后立场更极端最终只剩下两个对立的极端。"},
{"id":"5k-so-445","name":"信息的选择性接触","domain":"传播学","type_id":"36","description":"人们倾向于选择与自己观点一致的信息源回避矛盾信息——每次接触都在用支持性证据更新已有信念让信念越来越确定形成单向的信念强化。"},
{"id":"5k-so-446","name":"媒体事件的脉冲式关注","domain":"传播学","type_id":"78","description":"突发新闻引发关注度的瞬间飙升然后迅速回落下一个热点又引发新的脉冲——公众注意力呈突发性的脉冲模式而非持续稳定的关注。"},
{"id":"5k-so-447","name":"第三人效果","domain":"传播学","type_id":"36","description":"人们认为媒体对别人的影响比对自己大——对媒体效果的判断存在系统性偏差高估他人受影响程度低估自身受影响程度。"},
{"id":"5k-so-448","name":"传播网络中的意见领袖","domain":"传播学","type_id":"41","description":"信息传播网络中少数高连接度的意见领袖决定了什么内容能够广泛传播——影响力与粉丝数呈幂律关系极少数人拥有极大的传播能量。"},
{"id":"5k-so-449","name":"新闻价值的衰减","domain":"传播学","type_id":"06","description":"一条新闻的价值随时间快速贬值——发生当天关注度最高次日减半一周后几乎无人关心信息的新鲜度像放射性物质一样有半衰期。"},
{"id":"5k-so-450","name":"多媒体冗余效应","domain":"传播学","type_id":"58","description":"同一信息通过文字图片视频多渠道同时传递时记忆效果最好——多通道传递相当于信息的纠错编码即使某个通道出错其他通道也能保证信息完整接收。"},
{"id":"5k-so-451","name":"传播中的噪声累积","domain":"传播学","type_id":"55","description":"信息每经过一个传播节点都会混入一些噪声——经过多次中转后信号被噪声淹没接收者无法分辨原始信息信道的有效信息量随传播链长度下降。"},
{"id":"5k-so-452","name":"网络舆论的群体涌现","domain":"传播学","type_id":"72","description":"数百万条个人评论汇聚后形成了任何单条评论都没有的集体情绪和趋势——网络舆论是涌现现象整体的方向和强度无法从任何个体言论推导出来。"},
{"id":"5k-so-453","name":"流量分布的长尾","domain":"传播学","type_id":"35","description":"极少数爆款内容获得绝大部分流量而海量小众内容各自只有微少访问——流量分布呈重尾形态头部和尾部的差距可达百万倍。"},
{"id":"5k-so-454","name":"危机传播的时间压缩","domain":"传播学","type_id":"05","description":"社交媒体时代危机信息的传播速度呈指数增长——过去需要几天扩散的消息现在几小时就传遍全球留给组织反应的时间窗口被极度压缩。"},
{"id":"5k-so-455","name":"媒介依赖理论","domain":"传播学","type_id":"18","description":"社会越不确定人们越依赖媒体获取信息媒体影响力越大媒体越有能力塑造认知——不确定性和媒体依赖互相强化在危机时达到顶峰。"},
{"id":"5k-so-456","name":"说服的精细加工可能性","domain":"传播学","type_id":"24","description":"受众参与度高时被论据质量说服参与度低时被表面线索影响——参与度像一个分叉点把说服路径分为理性分析和直觉判断两条完全不同的通道。"},
{"id":"5k-so-457","name":"符号互动的意义建构","domain":"传播学","type_id":"70","description":"传播中的意义不是固定的而是在互动中不断重构——每一轮对话都在前一轮意义的基础上添加新层次形成递归式的意义生成过程。"},
{"id":"5k-so-458","name":"数字平台的网络外部性","domain":"传播学","type_id":"18","description":"社交平台用户越多内容越丰富内容越丰富越吸引新用户——用户数和内容量互相推动的正反馈让先发平台赢家通吃后来者几乎无法竞争。"},
{"id":"5k-so-459","name":"信息茧房的自我封闭","domain":"传播学","type_id":"13","description":"算法推荐让用户只看到感兴趣的内容兴趣更窄推荐更精准视野更窄兴趣更窄——信息获取和兴趣收窄在一个稳定的循环轨道上永续运转。"},
{"id":"5k-so-460","name":"公共对话的极化陷阱","domain":"传播学","type_id":"71","description":"网络讨论中极端声音因为更能引发回应而被算法放大温和声音被淹没——公共对话被锁定在极端化的稳定状态要恢复理性讨论需要外部力量打破。"},
{"id":"5k-so-461","name":"媒体内容的同质化","domain":"传播学","type_id":"71","description":"竞争压力下各媒体追踪热点互相抄袭最终内容高度趋同——信息市场的竞争力量把所有参与者拉向报道同样内容的不动点差异化反而不被奖励。"},
{"id":"5k-so-462","name":"传播效果的时间滞后","domain":"传播学","type_id":"22","description":"宣传和广告的效果往往不是立即显现而是在一段时间后才影响态度和行为——重复暴露的累积效应需要时间显现信息输入和态度改变之间有明显延迟。"},
{"id":"5k-so-463","name":"跨文化传播的折扣","domain":"传播学","type_id":"09","description":"信息跨越文化边界时影响力随文化距离增大而迅速减弱——在同文化圈内传播力最强相邻文化次之远距离文化几乎无影响。"},
{"id":"5k-so-464","name":"短视频的注意力捕获","domain":"传播学","type_id":"12","description":"短视频平台通过算法精确匹配用户的兴趣频率——当内容的刺激节奏恰好和用户的注意力偏好共振时沉浸感最强用户完全无法自拔。"},
{"id":"5k-so-465","name":"传播的小世界效应","domain":"传播学","type_id":"40","description":"社交网络中大部分人只和朋友圈交流但少数跨圈联系人让任何信息只需六步就能到达网络中的任何人——这种小世界结构让传播出人意料地快。"},
{"id":"5k-so-466","name":"假新闻的扩散优势","domain":"传播学","type_id":"42","description":"假新闻比真新闻传播更快更广因为它更新奇更情绪化——虚假信息在网络中的传染速度快于事实核查形成难以追赶的级联传播。"},
{"id":"5k-so-467","name":"品牌传播的记忆阈值","domain":"传播学","type_id":"23","description":"品牌广告需要达到一定的曝光次数才能在消费者记忆中留下印象——低于这个阈值投入几乎白费超过之后品牌认知突然建立形成从无到有的跃迁。"},
{"id":"5k-so-468","name":"舆论反转的相变","domain":"传播学","type_id":"25","description":"公众对某事件的集体判断有时会在新证据出现后瞬间翻转——从压倒性支持突然变成压倒性反对中间没有过渡就像物质的相变一样不连续。"},
{"id":"5k-so-469","name":"传播的信噪比优化","domain":"传播学","type_id":"57","description":"有效的传播策略在于最大化信号排除噪声——在注意力的有限带宽内选择最核心的信息去传递让有限的信道容量承载最关键的内容。"},
{"id":"5k-so-470","name":"叙事传播的情感共振","domain":"传播学","type_id":"12","description":"最有感染力的故事是情感节奏恰好与受众心理预期匹配的——紧张和释放的频率和观众的情感周期同步时共鸣最强传播效果最大化。"},
]
entries.extend(comm)

