entries.extend(pub)

# Write to file
output_path = "/Users/wanqh/projects/structural-isomorphism/data/kb-5k-social.jsonl"
with open(output_path, 'w', encoding='utf-8') as f:
    for entry in entries:
        f.write(json.dumps(entry, ensure_ascii=False) + '\n')

print(f"Total entries: {len(entries)}")
print(f"Written to: {output_path}")

# Verify domain counts
from collections import Counter
domains = Counter(e['domain'] for e in entries)
for d, c in sorted(domains.items(), key=lambda x: -x[1]):
    print(f"  {d}: {c}")

# Verify IDs
ids = [e['id'] for e in entries]
assert len(ids) == len(set(ids)), "Duplicate IDs found!"
assert ids[0] == "5k-so-001"
assert ids[-1] == "5k-so-500"
print("All IDs unique and correct range.")

# Verify type_id coverage
type_ids = set(e['type_id'] for e in entries)
print(f"Unique type_ids used: {len(type_ids)}")
